(()=>{'use strict';
const T=v=>String(v??'').trim(),N=v=>Number(String(v??'').replace(/,/g,''))||0,F=n=>N(n).toLocaleString('th-TH'),B=n=>N(n).toLocaleString('th-TH',{minimumFractionDigits:2,maximumFractionDigits:2});
const $=s=>document.querySelector(s),sorter=new Intl.Collator('th-u-kn-true',{numeric:true,sensitivity:'base'});
let fullPayload=null,fullRows=[],meta={};
function norm(s){return T(s).toLowerCase().replace(/[\s_\-./()[\]:]+/g,'')}
function cleanPs(v){const p=T(v).split(/\s+/).filter(Boolean);if(p.length===2&&p[0]===p[1])return p[0];const out=[];p.forEach(x=>{if(!out.includes(x))out.push(x)});return out.join(' ')}
function psList(){const a=(window.DOIT_SELECTED_PS_LIST||[]).map(cleanPs).filter(Boolean);if(a.length)return a;const p=cleanPs($('#psSelect')?.value);return p?[p]:[]}
function psKey(){const a=psList();return a.length?a.slice().sort((x,y)=>sorter.compare(x,y)).join('||'):''}
function psOk(r){const a=psList();return !a.length||a.includes(cleanPs(r.ps))}
function filters(){return{start:T($('#startDate')?.value),end:T($('#endDate')?.value),ps:psKey(),receiver:T($('#storeSelect')?.value),brand:T($('#brandSelect')?.value),type:T($('#typeSelect')?.value),q:T($('#q')?.value).toLowerCase()}}
function realTele(r){const tele=T(r.tele),ps=T(r.ps);if(!tele)return false;const kt=norm(tele),kp=norm(ps);if(kt&&kp&&(kt===kp||kp.includes(kt)||kt.includes(kp)))return false;return !!(r.isTele||tele)}
function appKey(){return meta.id||fullPayload?.version_id||meta.file_name||''}
function stateKey(){return 'doit-json:'+appKey()}
function manualKey(){return 'doit-manual-v1:'+appKey()}
function historyKey(){return 'doit-print-history-v1:'+appKey()}
function state(){try{return JSON.parse(localStorage.getItem(stateKey())||'{}')}catch{return{}}}
function saveState(s){localStorage.setItem(stateKey(),JSON.stringify(s||{}))}
function manuals(){try{return JSON.parse(localStorage.getItem(manualKey())||'[]')}catch{return[]}}
function saveManual(a){localStorage.setItem(manualKey(),JSON.stringify(a||[]))}
function history(){try{return JSON.parse(localStorage.getItem(historyKey())||'[]')}catch{return[]}}
function saveHistory(a){localStorage.setItem(historyKey(),JSON.stringify(a||[]))}
function scopeHead(){const f=filters();return[f.start,f.end,f.ps].join('|')+'|'}
function pk(r){return [r.brand,r.size,r.code||r.sku,r.sku,r.type].join('|')}
function pkFromKey(k){return String(k).split('|').slice(4).join('|')}
function recFromKey(k){return String(k).split('|')[3]||''}
function scopeRows(){const f=filters();return fullRows.filter(r=>!realTele(r)&&psOk(r)&&(!f.start||r.date>=f.start)&&(!f.end||r.date<=f.end)&&(!f.brand||r.brand===f.brand)&&(!f.type||r.type===f.type)&&(!f.q||[r.date,r.inv,r.code,r.sku,r.store,r.ps,r.brand,r.size,r.type].join(' ').toLowerCase().includes(f.q)))}
function group(rows=scopeRows()){const m=new Map();rows.forEach(r=>{const k=pk(r);let g=m.get(k);if(!g){g={poolKey:k,brand:r.brand,size:r.size,code:r.code,sku:r.sku,type:r.type,qty:0,amt:0,unit:r.unit||0,bills:new Set(),stores:new Set()};m.set(k,g)}g.qty+=N(r.qty);g.amt+=N(r.amt);g.unit=g.qty&&g.amt?g.amt/g.qty:g.unit;g.bills.add(r.inv);g.stores.add(r.store)});return[...m.values()].sort((a,b)=>sorter.compare(a.brand,b.brand)||sorter.compare(a.size,b.size)||sorter.compare(a.code||'',b.code||'')||sorter.compare(a.sku,b.sku))}
function manualInScope(storeOnly=false){const f=filters();return manuals().filter(x=>(!f.start||x.start===f.start)&&(!f.end||x.end===f.end)&&(!f.ps||x.ps===f.ps)&&(!storeOnly||!f.receiver||x.store===f.receiver))}
function deliveryLines(){const f=filters(),st=state(),send=st.send||{},gmap=new Map(group(scopeRows().filter(r=>!f.q)).map(g=>[g.poolKey,g])),out=[];Object.keys(send).filter(k=>k.startsWith(scopeHead())).forEach(k=>{const q=N(send[k]);if(q<=0)return;const g=gmap.get(pkFromKey(k)),rec=recFromKey(k);if(g&&rec)out.push({store:rec,code:g.code||'',name:g.sku,brand:g.brand,size:g.size,type:g.type,qty:q,unit:g.unit||0,manual:false})});manualInScope(true).forEach(x=>out.push({store:x.store,code:x.code||'',name:x.name,brand:x.brand||'เพิ่มเอง',size:x.size||'',type:x.type||'MANUAL',qty:N(x.qty),unit:N(x.unit),manual:true,id:x.id}));return out.sort((a,b)=>sorter.compare(a.store,b.store)||sorter.compare(a.brand,b.brand)||sorter.compare(a.size,b.size)||sorter.compare(a.code,b.code)||sorter.compare(a.name,b.name))}
function refresh(){try{document.body.classList.remove('printMode');$('#doitPrintOverlay')?.remove();window.DOIT_JSON_APP?.rerender?.()||document.dispatchEvent(new CustomEvent('doit:stateChanged'))}catch(e){console.warn('[field-logic-fixes-v295] refresh failed',e)}}
function closeStore(saveHist){const f=filters();if(!f.receiver){alert('กรุณาเลือกร้านจริงก่อนปิดบิลหรือล้างร้าน');return}const st=state(),head=[f.start,f.end,f.ps,f.receiver].join('|')+'|',removed=[];['send','add','pull'].forEach(k=>{const obj=st[k]||{};Object.keys(obj).forEach(x=>{if(x.startsWith(head)){removed.push({map:k,key:x,qty:N(obj[x])});delete obj[x]}});st[k]=obj});const ms=manuals(),keep=[];ms.forEach(x=>{if(x.store===f.receiver&&x.start===f.start&&x.end===f.end&&x.ps===f.ps){removed.push({map:'manual',item:x})}else keep.push(x)});if(!removed.length){alert('ร้านนี้ไม่มีรายการค้างในช่วงวันที่/PS นี้');return}if(saveHist){const h=history();h.unshift({at:new Date().toISOString(),store:f.receiver,start:f.start,end:f.end,ps:f.ps,items:deliveryLines().filter(x=>x.store===f.receiver)});saveHistory(h.slice(0,200))}saveState(st);saveManual(keep);alert(saveHist?'ปิดบิลและเก็บเข้า History แล้ว':'ล้างรายการของร้านนี้แล้ว');refresh()}
function patchLoad(){const app=window.DOIT_JSON_APP;if(!app||app.__fieldLogic295)return false;const old=app.load.bind(app);app.load=(payload,m={})=>{meta=m||{};fullPayload=payload;const arr=payload?.rows||payload||[];fullRows=Array.isArray(arr)?arr.map(r=>({date:T(r.date),inv:T(r.inv),store:T(r.store),tele:T(r.tele),isTele:!!r.isTele,ps:cleanPs(r.ps),code:T(r.code),sku:T(r.sku),brand:T(r.brand),size:T(r.size),type:T(r.type)||'INVC',qty:N(r.qty),unit:N(r.unit),amt:N(r.amt)})):[];window.__doitAllRows=fullRows;window.DOIT_SELECTED_PS_KEY=psKey();const list=psList();const set=new Set(list);const filtered=list.length?fullRows.filter(r=>set.has(cleanPs(r.ps))):fullRows;const next=Array.isArray(payload)?filtered:{...payload,rows:filtered};return old(next,m)};app.rerender=()=>{if(fullPayload)app.load(fullPayload,meta)};app.__fieldLogic295=true;return true}
function patchTelesale(){const d=window.DOIT_TELESALE_DRAWER;if(!d||d.__fieldLogic295||!d.loadRows)return false;const old=d.loadRows.bind(d);d.loadRows=(data,ctx={})=>old(fullRows.length?fullRows:data,{...ctx,psList:psList(),psKey:psKey()});d.__fieldLogic295=true;return true}
function patchRemaining(){if(window.__fieldRemain295)return;window.__fieldRemain295=true;document.addEventListener('click',e=>{if(e.target?.id!=='remainSummaryBtn')return;setTimeout(()=>{const old=$('#remainOverlay');if(!old)return;old.remove();openRemainSummary()},0)},true)}
function openRemainSummary(){const data=buildRemain();const f=filters();let st=$('#remainSummaryCss295');if(!st){st=document.createElement('style');st.id='remainSummaryCss295';st.textContent='#remainOverlay{position:fixed;inset:0;background:rgba(15,23,42,.55);z-index:9998;display:flex;align-items:flex-end}#remainPanel{background:#fff;width:100%;max-height:88vh;border-radius:18px 18px 0 0;overflow:auto;color:#111827}#remainHead{position:sticky;top:0;background:#087b34;color:#fff;padding:10px 12px;display:flex;justify-content:space-between;gap:8px;align-items:center}#remainHead button{height:34px;border:1px solid #fff;background:#fff;color:#087b34;border-radius:8px;font-weight:900;padding:0 10px}.remainNote{padding:10px;color:#4b5563;font-size:12px}.remainWrap{overflow:auto;padding:0 10px 12px}.remainTbl{width:100%;border-collapse:collapse;min-width:760px;font-size:12px}.remainTbl th,.remainTbl td{border:1px solid #e5e7eb;padding:7px;text-align:center}.remainTbl th{background:#f8fafc}.remainTbl td:nth-child(1),.remainTbl th:nth-child(1),.remainTbl td:nth-child(3),.remainTbl th:nth-child(3){text-align:left}.remainNeg{color:#dc2626;font-weight:950}.remainPos{color:#111827;font-weight:900}.remainZero{color:#15803d;font-weight:900}';document.head.appendChild(st)}const ov=document.createElement('div');ov.id='remainOverlay';ov.innerHTML=`<section id="remainPanel"><div id="remainHead"><div><b>สรุปของเหลือ</b><br><small>วันที่ ${esc(f.start)} - ${esc(f.end)} · PS ${esc(f.ps||'ทั้งหมด')} · ไม่รวม Telesale</small></div><span><button id="remainCsv">Export</button> <button id="remainClose">ปิด</button></span></div><div class="remainNote">ของเหลือ = จำนวนคีย์ - จำนวนที่ส่ง/ปิดบิล/ค้างส่ง. ถ้าส่งเกินจะแสดงติดลบสีแดง เช่น -1</div><div class="remainWrap"><table class="remainTbl"><thead><tr><th>ชื่อสินค้า</th><th>จำนวนคีย์</th><th>ร้านที่ส่ง</th><th>ของเหลือ</th></tr></thead><tbody>${data.map(r=>`<tr><td>${esc(r.name)}<br><small>${esc(r.code||'')}</small></td><td>${F(r.keyed)}</td><td>${esc(r.stores)}</td><td class="${r.remain<0?'remainNeg':(r.remain===0?'remainZero':'remainPos')}">${F(r.remain)}</td></tr>`).join('')||'<tr><td colspan="4">ไม่พบข้อมูล</td></tr>'}</tbody></table></div></section>`;document.body.appendChild(ov);$('#remainClose').onclick=()=>ov.remove();$('#remainCsv').onclick=()=>downloadRemainCsv(data);ov.onclick=e=>{if(e.target===ov)ov.remove()}}
function esc(s){return T(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function add(map,k,n){map.set(k,(map.get(k)||0)+N(n))}
function addStore(stores,k,store,qty){store=T(store)||'ไม่ระบุร้าน';if(!stores.has(k))stores.set(k,new Map());const m=stores.get(k);m.set(store,(m.get(store)||0)+N(qty))}
function setLabel(labels,k,x){if(!labels.has(k))labels.set(k,{key:k,brand:T(x.brand),size:T(x.size),code:T(x.code),name:T(x.sku||x.name)||k,type:T(x.type),manual:!!x.manual})}
function pkFromData(x){if(x.poolKey)return x.poolKey;if(x.manual)return['MANUAL',x.id||'',x.store||'',x.brand||'',x.code||'',x.name||x.sku||'',x.type||''].join('|');const name=T(x.name||x.sku);return[x.brand||'',x.size||'',x.code||name,name,x.type||''].join('|')}
function buildRemain(){const f=filters(),order=new Map(),sent=new Map(),stores=new Map(),labels=new Map();scopeRows().forEach(r=>{const k=pk(r);add(order,k,r.qty);setLabel(labels,k,r)});history().forEach(h=>{if(h.start!==f.start||h.end!==f.end||h.ps!==f.ps)return;(h.items||[]).forEach(x=>{const k=pkFromData(x);add(sent,k,x.qty);addStore(stores,k,x.store||h.store,x.qty);setLabel(labels,k,{...x,sku:x.name||x.sku})})});const send=state().send||{};Object.keys(send).filter(k=>k.startsWith(scopeHead())).forEach(key=>{const qty=N(send[key]);if(qty<=0)return;const k=pkFromKey(key),store=recFromKey(key);add(sent,k,qty);addStore(stores,k,store,qty)});manualInScope(false).forEach(x=>{const k=pkFromData({...x,manual:true});add(sent,k,x.qty);addStore(stores,k,x.store,x.qty);setLabel(labels,k,{...x,sku:x.name,manual:true})});const keys=new Set([...order.keys(),...sent.keys()]);return[...keys].map(k=>{const l=labels.get(k)||{key:k,name:k,brand:'',size:'',code:'',type:''};const keyed=N(order.get(k)),sentQty=N(sent.get(k)),remain=keyed-sentQty;const storeText=[...(stores.get(k)||new Map()).entries()].filter(([,q])=>N(q)).sort((a,b)=>sorter.compare(a[0],b[0])).map(([s,q])=>`${s} ${F(q)}`).join(', ');return{...l,keyed,sent:sentQty,stores:storeText||'-',remain}}).sort((a,b)=>sorter.compare(a.brand,b.brand)||sorter.compare(a.size,b.size)||sorter.compare(a.code||'',b.code||'')||sorter.compare(a.name,b.name))}
function downloadRemainCsv(data){const out=[['ชื่อสินค้า','จำนวนคีย์','ร้านที่ส่ง','ของเหลือ']];data.forEach(r=>out.push([r.name,r.keyed,r.stores,r.remain]));const blob='\ufeff'+out.map(a=>a.map(x=>'"'+String(x??'').replace(/"/g,'""')+'"').join(',')).join('\n');const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([blob],{type:'text/csv;charset=utf-8'}));a.download='doit-remaining-summary-simple.csv';a.click()}
function patchClicks(){if(document.__fieldLogic295Click)return;document.__fieldLogic295Click=true;document.addEventListener('click',e=>{const id=e.target?.id;if(id==='doitConfirmPrint'||id==='closeBillBtn'||id==='clearStoreBtn'){e.preventDefault();e.stopImmediatePropagation();closeStore(id!=='clearStoreBtn')}},true)}
function boot(){try{window.sshape=false}catch{}patchLoad();patchTelesale();patchRemaining();patchClicks();let n=0;const tick=()=>{try{window.sshape=false}catch{}patchLoad();patchTelesale();if(++n<30)setTimeout(tick,300)};setTimeout(tick,300)}
document.addEventListener('DOMContentLoaded',boot);if(document.readyState!=='loading')boot();
})();